-- Tabla de proyectos CREATE TABLE proyectos ( id INTEGER PRIMARY KEY AUTOINCREMENT, nombre TEXT NOT NULL UNIQUE, url_general_html TEXT NOT NULL, url_detallada_html TEXT NOT NULL ); -- Tabla de archivos dentro de src/ CREATE TABLE archivos_src ( id INTEGER PRIMARY KEY AUTOINCREMENT, proyecto_id INTEGER NOT NULL, nombre TEXT NOT NULL, download_url TEXT NOT NULL, FOREIGN KEY(proyecto_id) REFERENCES proyectos(id) ON DELETE CASCADE );
